import React, { useState } from 'react';
import api from '../api';

const InvestmentForm = ({ onAdd }) => {
  const [principal, setPrincipal] = useState('');
  const [rate, setRate] = useState('');
  const [duration, setDuration] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await api.post('/investments', { principal: parseFloat(principal), rate: parseFloat(rate), duration: parseInt(duration) });
      onAdd();
      setPrincipal('');
      setRate('');
      setDuration('');
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 rounded-lg shadow mb-6">
      <h3 className="text-xl font-bold mb-4">Add Investment</h3>
      <div className="space-y-4">
        <input type="number" value={principal} onChange={(e) => setPrincipal(e.target.value)} placeholder="Principal $" className="w-full p-3 border rounded-lg" required />
        <input type="number" step="0.01" value={rate} onChange={(e) => setRate(e.target.value)} placeholder="Annual Rate %" className="w-full p-3 border rounded-lg" required />
        <input type="number" value={duration} onChange={(e) => setDuration(e.target.value)} placeholder="Duration Years" className="w-full p-3 border rounded-lg" required />
        <button type="submit" className="w-full bg-purple-500 text-white p-3 rounded-lg font-semibold">Add Investment</button>
      </div>
    </form>
  );
};

export default InvestmentForm;
